INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('_RJbVN6pdtaI', 'Genetik in 30 Sekunden', 'Jonathan Weitzman; Matthew Weitzman', 2014, 'Science', 'science', 'German', '9789089988812', 'Librero', 160, 4.6, 'https://www.amazon.de/dp/1782405475', 'https://www.librero-ibp.com/uploads/product/thumb/genetik-in-30-sekunden-1692626675.jpg', 'This comprehensive presentation of the core concepts and historical landmarks in robotics and artificial intelligence is a must-read for those who want to understand the important changes happening now in our everyday lives, in the workplace, and in our minds and bodies. What is deep in "deep learning"? Can artificial intelligence really think? What will robots really look like in the near future? Is there a new class divide between those who understand technology and those who fear it? A clear and exhaustive introduction for non-specialists, 30-Second AI & Robotics will help the reader to navigate the world of ubiquitous computers, smart cities, and collaborative robots. At last, an optimistic and friendly book about our human possibilities in the time of automata.', 'pax-audit-verlag-librero', '2026-05-12 08:14:05', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('tC_qd23AduIY', 'Swiss Made', 'R. James Breiding', 2012, 'Non-fiction', 'non-fiction', 'English', '9781898948202', 'Profile Books', 432, 3.94, 'https://www.amazon.com/dp/1898948201', 'https://covers.openlibrary.org/b/id/15195961-L.jpg', 'A comprehensive exploration of Switzerland''s economic success, "Swiss Made" by R. James Breiding delves into the factors contributing to the country''s global reputation for innovation, stability, and wealth. The book examines a range of industries, from finance and pharmaceuticals to technology and watchmaking, highlighting the cultural and historical influences that have shaped Switzerland''s unique business environment.', 'pax-audit-openlibrary', '2026-05-12 19:20:15', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('DJHRCgRo04-T', 'Der Crash kommt', 'Max Otte', 2008, 'Economics', 'finance', 'German', '9783426306253', 'Droemer Knaur', 384, 3.8, 'https://www.amazon.de/dp/3426306254', 'https://covers.openlibrary.org/b/id/8397828-L.jpg', 'An analysis of economic trends and warnings about an impending financial crisis, "Der Crash kommt" by Max Otte anticipates the economic challenges and disruptions that could lead to a significant market crash.', 'pax-audit-openlibrary', '2026-05-12 08:12:26', '2026-05-11 23:09:48', '2026-05-13 13:21:41');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('cjiXHYQF4K1Q', 'Crashkurs – Dirk Müller', 'Dirk Müller', 2009, 'Economics', 'finance', 'German', '978-3938350149', 'Droemer Knaur', 256, 4.4, 'https://www.amazon.de/dp/3938350140', 'https://books.google.com/books/content?id=goyoGQAACAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api', 'An engaging exploration of global financial markets, "Crashkurs" by Dirk Müller breaks down complex economic concepts for readers. Published in 2009, it offers insights into the causes and repercussions of the financial crisis, guiding readers through economic theories with practical advice and solutions. Known for his clear and approachable style, Müller provides a unique perspective from his experience in finance.', 'original', '2026-05-12 08:11:06', '2026-05-11 23:09:48', '2026-05-13 13:21:41');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('raSRTUkjjLrZ', 'Six Sigma für Dummies', 'Craig Gygi / Bruce Williams / Neil DeCarlo', 2005, 'Non-fiction', 'non-fiction', 'German', '978-0470045190', 'Wiley', 384, 3.74, 'https://www.amazon.de/dp/0470045191', 'https://covers.openlibrary.org/b/id/8720010-L.jpg', 'Includes index.', 'open_library', '2026-05-12 19:15:30', '2026-05-11 23:09:48', '2026-05-12 19:15:30');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('E5uENuxFdwOr', 'Statistik mit Excel für Dummies', 'Joseph Schmuller', 2005, 'Non-Fiction', 'non-fiction', 'German', '978-3527713643', 'Wiley-VCH', 424, 4.3, NULL, 'https://covers.openlibrary.org/b/id/3225449-L.jpg', 'A comprehensive guide to using Excel for statistical analysis, this book simplifies complex statistical concepts and techniques, making them accessible for beginners. Written by Joseph Schmuller, it covers data analysis, hypothesis testing, and regression, providing practical examples and step-by-step instructions for leveraging Excel''s powerful features.', 'pax-audit-openlibrary', '2026-05-12 19:19:33', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('DOU7tony9Fgo', 'Übungsbuch Statistik für Dummies', 'Deborah J. Rumsey', 2024, 'Non-Fiction', 'non-fiction', 'German', '3527707071', 'Wiley-VCH', 368, 4.5, 'https://www.amazon.de/dp/3527707071', 'https://covers.openlibrary.org/b/id/14671956-L.jpg', 'A practical guide for students and professionals, providing clear explanations and exercises to master statistical concepts effectively.', 'pax-audit-openlibrary', '2026-05-12 20:57:00', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('ocTmmscYYc87', 'Statistik für Dummies', 'Deborah J. Rumsey', 2003, 'Non-fiction', 'non-fiction', 'German', '978-3-527-71018-1', 'Wiley-VCH', 352, NULL, 'https://www.amazon.de/dp/3527710182', 'https://covers.openlibrary.org/b/id/13809998-L.jpg', 'A comprehensive guide to understanding and applying statistical concepts, tailored for beginners. It breaks down complex ideas into simple, easy-to-follow explanations with practical examples, making it accessible for readers without a background in statistics.', 'original', '2026-05-12 19:18:41', '2026-05-11 23:09:48', '2026-05-12 19:18:41');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('fh8gVaj1Wcxo', 'Logik für Dummies', 'Mark Zegarelli', 2016, 'Non-Fiction', 'non-fiction', 'German', '9783527711031', 'Wiley-VCH', 335, 4.5, 'https://www.amazon.de/dp/3527711030', 'https://covers.openlibrary.org/b/id/12402281-L.jpg', 'Ein verständlicher Leitfaden zur Logik, der komplexe Konzepte in greifbare und leicht verständliche Schritte zerlegt. Ideal für Einsteiger, die ihr Verständnis der logischen Prinzipien aufbauen wollen, bietet das Buch klare Erklärungen und praxisorientierte Beispiele.', 'pax-audit-openlibrary', '2026-05-12 08:15:11', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('vT4kARjSbiAc', 'XML für Dummies', 'Lucinda Dykes / Ed Tittel', 2005, 'Non-fiction', 'non-fiction', 'German', '978-3-527-70129-0', 'Wiley', 352, 4.2, NULL, 'https://covers.openlibrary.org/b/id/3225469-L.jpg', 'A beginner-friendly guide to understanding and using XML, covering basic concepts, practical applications, and expert tips for navigating this essential web technology.', 'original', '2026-05-12 19:39:14', '2026-05-11 23:09:48', '2026-05-12 19:39:14');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('klOfBdC281sw', 'Zeitmanagement für Dummies', 'Dirk Mayer', 2007, 'Self-help', 'self-help', 'German', '978-3527519303', 'Wiley-VCH', 352, 4.5, 'https://www.amazon.de/dp/3527519304', 'https://covers.openlibrary.org/b/id/2216020-L.jpg', NULL, 'pax-audit-openlibrary', '2026-05-12 19:40:04', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_6bc7a4389671', 'Wahrscheinlichkeitsrechnung für Dummies', 'Deborah Rumsey', 2007, 'Nonfiction', 'non-fiction', 'German', '978-3-527-70351-7', 'Wiley', 360, 4.0, NULL, 'https://covers.openlibrary.org/b/id/3225551-L.jpg', 'Ein umfassendes und zugängliches Buch, das die Grundlagen der Wahrscheinlichkeitsrechnung erklärt, ideal für Einsteiger ohne Vorwissen.', 'original', '2026-05-12 19:25:12', '2026-05-11 23:09:48', '2026-05-12 19:25:12');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_24509925f484', 'Mathe in 30 Sekunden', 'Richard J. Brown', 2012, 'Mathematics', 'science', 'German', '978-3-8310-2185-4', 'Dodax AG', 160, 3.59, 'https://www.dodax.de/de-de/buecher-hoerbuecher/mathematik/mathe-in-30-sekunden-richard-j-brown-dpI1Q50O9360/', 'https://books.google.com/books/content?id=y9J3MAEACAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api', '"Mathe in 30 Sekunden" by Richard J. Brown is a concise exploration of key mathematical concepts, designed to explain complex ideas in brief, easily digestible segments. Each topic is intended to take 30 seconds to understand, making it an accessible resource for anyone interested in the fundamentals of mathematics. The book covers a wide range of topics from geometry to calculus, providing an engaging summary of essential mathematical principles.', 'original', '2026-05-12 08:15:54', '2026-05-11 23:09:48', '2026-05-13 13:21:41');
