INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('IB83F_KcAMLt', 'Credit Risk Modeling using Excel and VBA', 'Gunter Löffler; Peter N. Posch', 2011, 'Finance', 'finance', 'English', '9780470660928', 'Wiley', 326, 3.8, 'https://www.wiley.com/en-us/Credit+Risk+Modeling+using+Excel+and+VBA-p-9780470660928', 'https://covers.openlibrary.org/b/id/12577706-L.jpg', 'It is common to blame the inadequacy of credit risk models for the fact that the financial crisis has caught many market participants by surprise. On closer inspection, though, it often appears that market participants failed to understand or to use the models correctly. The recent events therefore do not invalidate traditional credit risk modeling as described in the first edition of the book. A second edition is timely, however, because the first dealt relatively briefly with instruments featuring prominently in the crisis (CDSs and CDOs). In addition to expanding the coverage of these instruments, the book will focus on modeling aspects which were of particular relevance in the financial crisis (e.g. estimation error) and demonstrate the usefulness of credit risk modelling through case studies. This book provides practitioners and students with an intuitive, hands-on introduction to modern credit risk modelling. Every chapter starts with an explanation of the methodology and then the authors take the reader step by step through the implementation of the methods in Excel and VBA. They focus specifically on risk management issues and cover default probability estimation (scoring, structural models, and transition matrices), correlation and portfolio analysis, validation, as well as credit default swaps and structured finance. The book has an accompanying website, https://creditriskmodeling.wordpress.com/, which has been specially updated for this Second Edition and contains slides and exercises for lecturers.', 'google_books', '2026-05-12 08:12:10', '2026-05-11 23:09:48', '2026-05-12 08:12:10');
