INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('rNCGaoOV0CWb', 'MasterClass: Tony Buzan', 'Tony Buzan', NULL, 'Non-Fiction', 'non-fiction', 'English', NULL, 'Watkins Publishing; Watkins Publishing Ltd.', NULL, 3.9, NULL, 'https://images-na.ssl-images-amazon.com/images/I/41Hx-4kdZ8L._SX362_BO1,204,203,200_.jpg', 'A comprehensive guide by Tony Buzan on enhancing mental abilities and learning techniques, focusing on memory improvement, speed reading, and mind mapping strategies.', 'original', '2026-05-12 08:15:45', '2026-05-11 23:09:48', '2026-05-11 23:10:20');
