INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('9tZ0Ed7kAv7r', 'Market Risk Analysis, Vol. I: Quantitative Methods in Finance', 'Carol Alexander', 2008, 'Finance', 'finance', 'English', '9780470998007', 'John Wiley & Sons', 428, NULL, 'https://www.amazon.com/dp/0470998009', 'https://covers.openlibrary.org/b/id/8691268-L.jpg', 'Comprehensive introduction to quantitative methods in finance, focusing on statistical techniques essential for market risk analysis and covering topics such as probability, statistical inference, and multivariate analysis.', 'pax-audit-openlibrary', '2026-05-12 08:15:26', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('icxsCAz7jkI2', 'Market Risk Analysis, Vol. II: Practical Financial Econometrics', 'Carol Alexander', 2008, 'Finance/Economics', 'finance', 'English', '978-0470998005', 'Wiley; John Wiley & Sons', 439, NULL, NULL, 'https://books.google.com/books/content?id=M0JZwwEACAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api', 'Written by leading market risk academic, Professor Carol Alexander, Quantitative Methods in Finance forms part one of the Market Risk Analysis four volume set. Starting from the basics, this book helps readers to take the first step towards becoming a properly qualified financial risk manager and asset manager, roles that are currently in huge demand. Accessible to intelligent readers with a moderate understanding of mathematics at high school level or to anyone with a university degree in mathematics, physics or engineering, no prior knowledge of finance is necessary. Instead the emphasis is on understanding ideas rather than on mathematical rigour, meaning that this book offers a fast-track introduction to financial analysis for readers with some quantitative background, highlighting those areas of mathematics that are particularly relevant to solving problems in financial risk management and asset management. Unique to this book is a focus on both continuous and discrete time finance so that Quantitative Methods in Finance is not only about the application of mathematics to finance; it also explains, in very pedagogical terms, how the continuous time and discrete time finance disciplines meet, providing a comprehensive, highly accessible guide which will provide readers with the tools to start applying their knowledge immediately. All together, the Market Risk Analysis four volume set illustrates virtually every concept or formula with a practical, numerical example or a longer, empirical case study. Across all four volumes there are approximately 300 numerical and empirical examples, 400 graphs and figures and 30 case studies many of which are contained in interactive Excel spreadsheets available from the accompanying CD-ROM . Empirical examples and case studies specific to this volume include: Principal component analysis of European equity indices; Calibration of Student t distribution by maximum likelihood; Orthogonal regression and estimation of equity factor models; Simulations of geometric Brownian motion, and of correlated Student t variables; Pricing European and American options with binomial trees, and European options with the Black-Scholes-Merton formula; Cubic spline fitting of yields curves and implied volatilities; Solution of Markowitz problem with no short sales and other constraints; Calculation of risk adjusted performance metrics including generalised Sharpe ratio, omega and kappa indices.', 'google_books', '2026-05-12 08:15:32', '2026-05-11 23:09:48', '2026-05-13 13:21:41');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('0ILKr91IJxYr', 'Market Risk Analysis, Vol. IV: Value-at-Risk Models', 'Carol Alexander', 2008, 'Finance', 'finance', 'English', '9780470998014', 'John Wiley & Sons', 348, NULL, 'https://www.amazon.com/dp/0470998010', 'https://covers.openlibrary.org/b/id/8691268-L.jpg', 'An authoritative guide to the latest value-at-risk models, focusing on risk management techniques for measuring and controlling market risk. This volume offers practical insights into model implementation and evaluation, catering to professionals and academics in finance.', 'pax-audit-openlibrary', '2026-05-12 08:15:35', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
