INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('6r6T20vq5oOS', 'Forex Conquered', 'John L. Person', 2007, 'Finance', 'finance', 'English', '9780470127049', 'John Wiley & Sons', 306, NULL, NULL, 'https://covers.openlibrary.org/b/id/1239425-L.jpg', 'Praise for FOREX CONQUERED "In this amazing book, John covers it all. From trading systemsto money management to emotions, he explains easily how to pullmoney consistently from the most complicated financial market inthe world. John packs more new, innovative information into thisbook than I have ever seen in a trading book before." —Rob Booker, independent currency trader "John Person is one of the few rare talents that are uniquelyqualified to help traders understand the process of successfultrading. With today''s markets becoming increasingly challenging,John has cut right into the essentials and brought forward themuch-needed tools of forex trading. This clear and well-organizedpublication is a major step forward in helping traders gain anedge. I would highly recommend Forex Conquered as a valuablehandbook for both aspiring and experienced traders alike." —Sandy Jadeja, Chief Market Analyst and EditorLondon StockExchange, London, England "Forex Conquered is a bold title, but this book deliversthe tools needed for successful forex trading. There is no fluffhere, just the wisdom of a trading veteran that I have alwaysrespected-and followed." —Michael Kahn, Editor, Quick Takes Pro market letterand Columnist, Barron''s Online "This is a wonderful, in-depth view into the explanation oftechnical analysis and prudent money management guidelines in theforex market." —Blake Morrow, President, 4XMadeEasy "Forex Conquered is a meaningful contribution to the growingnumber of books on forex trading. John Person provides aprofessional view of forex trading that readers will be able to useas a guide for strategies and tactics that work. The scope of thebook covers more than forex and includes salient aspects of futuresand option trading. It should be read and then re-read!" —Abe Cofnas, President, Learn4x.com Note: CD-ROM/DVD and other supplementary materials arenot included as part of eBook file.', 'google_books', '2026-05-12 08:13:42', '2026-05-11 23:09:48', '2026-05-12 08:13:42');
