INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('kkk1HBojmskY', 'Asterix – Gesamtausgabe, Band 4', 'René Goscinny; Albert Uderzo', 2014, 'Comics', 'comics', 'German', '978-3-7704-3724-5', 'Egmont Ehapa Verlag', 144, NULL, NULL, 'https://www.egmont-shop.de/globalassets/01_egmont-catalog/37343724/asterix_gesamtausgabe_-_band_04_-_gebundene_ausgabe.png', 'Band 4 der Asterix-Gesamtausgabe vereint drei Abenteuer rund um militärische und sportliche Herausforderungen: ''Asterix als Legionär'' (Falbalas Verlobter Tragicomix wird gerettet), ''Asterix und der Arvernerschild'' (Majestix erbt das Symbol Vercingetorix'' und Cäsar will es) und ''Asterix bei den Olympischen Spielen'' (Wettkampf in Olympia gegen Claudius Musculus). Neu koloriert, mit Vorworten von Horst Berner.', 'pax-research', '2026-05-12 08:10:03', '2026-05-11 23:09:48', '2026-05-13 12:06:30');
