INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('2hh--Og3q9fv', 'Asterix – Gesamtausgabe, Band 2', 'René Goscinny; Albert Uderzo', 2014, 'Comics', 'comics', 'German', '978-3-7704-3783-2', 'Egmont Ehapa Verlag', 144, 4.5, NULL, 'https://www.egmont-shop.de/globalassets/01_egmont-catalog/37343783/asterix_gesamtausgabe_-_band_02_gebundene_ausgabe.png', 'Band 2 der Asterix-Gesamtausgabe versammelt drei der beliebtesten Reise-Abenteuer: ''Asterix als Gladiator'' (Rettung des entführten Troubadix in Rom), ''Tour de France'' (kulinarische Rundreise durch Gallien) und ''Asterix und Kleopatra'' (Hilfe beim Palastbau für die Pharaonin). Sorgfältig neu koloriert, mit Hintergrund-Essays von Horst Berner.', 'pax-research', '2026-05-12 08:09:28', '2026-05-11 23:09:48', '2026-05-13 12:06:30');
