INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('O6WqE3XTpgJJ', 'Der Wüstenkrieg in Afrika', 'Janusz Piekalkiewicz', 1984, 'Military History', 'history', 'German', '9783828903579', 'Weltbild', 288, NULL, NULL, 'https://exlibris.azureedge.net/covers/9783/8289/0357/9/9783828903579xxl.webp', 'A comprehensive account of the North African conflict during World War II, exploring key battles, strategies, and military leaders, with detailed analyses and historical photographs. Published in 1984, this work by Janusz Piekalkiewicz offers an in-depth exploration of the war efforts in the desert landscapes of Africa.', 'pax-audit-exlibris-ch', '2026-05-12 08:12:51', '2026-05-11 23:09:48', '2026-05-13 13:21:41');
