INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('6Dr0HH2evyuI', 'Invasion', 'Janusz Piekalkiewicz', 1974, 'History', 'history', 'English', '9783828902794', 'Herbig Publishing House', 320, 4.2, NULL, 'https://covers.openlibrary.org/b/id/11410901-L.jpg', 'A historical account examining the strategies, tactics, and events of significant military invasions, detailing the complexities and consequences of these operations throughout history. Published in 1974 by Janusz Piekalkiewicz, this work offers insights into military history with an emphasis on factual reporting and analysis.', 'original', '2026-05-12 08:15:00', '2026-05-11 23:09:48', '2026-05-12 08:15:00');
