INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('e7olJ1w1qCSW', 'Der Zweite Weltkrieg', 'R. Oldenbourg', 1985, 'History', 'history', 'German', '9783486588316', 'Oldenbourg Verlag', 450, NULL, NULL, 'https://books.google.com/books/content?id=FiK50AEACAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api', 'A comprehensive examination of the events, strategies, and key figures of World War II, providing insights into the global impact and historical significance of the conflict. Published in 1985 by author R. Oldenbourg, this work delves into the detailed narratives and analysis that shaped the course of 20th-century history.', 'original', '2026-05-12 08:12:55', '2026-05-11 23:09:48', '2026-05-12 08:12:55');
