INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-_RJbVN6pdtaI', 'Genetik in 30 Sekunden', 'This comprehensive presentation of the core concepts and historical landmarks in robotics and artificial intelligence is a must-read for those who want to understand the important changes happening now in our everyday lives, in the workplace, and in our minds and bodies. What is deep in "deep learning"? Can artificial intelligence really think? What will robots really look like in the near future? Is there a new class divide between those who understand technology and those who fear it? A clear and exhaustive introduction for non-specialists, 30-Second AI & Robotics will help the reader to navigate the world of ubiquitous computers, smart cities, and collaborative robots. At last, an optimistic and friendly book about our human possibilities in the time of automata.', 'book', '["jonathan-weitzman", "matthew-weitzman"]', '["science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-tC_qd23AduIY', 'Swiss Made', 'A comprehensive exploration of Switzerland''s economic success, "Swiss Made" by R. James Breiding delves into the factors contributing to the country''s global reputation for innovation, stability, and wealth. The book examines a range of industries, from finance and pharmaceuticals to technology and watchmaking, highlighting the cultural and historical influences that have shaped Switzerland''s unique business environment.', 'book', '["r-james-breiding"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-DJHRCgRo04-T', 'Der Crash kommt', 'An analysis of economic trends and warnings about an impending financial crisis, "Der Crash kommt" by Max Otte anticipates the economic challenges and disruptions that could lead to a significant market crash.', 'book', '["max-otte"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-cjiXHYQF4K1Q', 'Crashkurs – Dirk Müller', 'An engaging exploration of global financial markets, "Crashkurs" by Dirk Müller breaks down complex economic concepts for readers. Published in 2009, it offers insights into the causes and repercussions of the financial crisis, guiding readers through economic theories with practical advice and solutions. Known for his clear and approachable style, Müller provides a unique perspective from his experience in finance.', 'book', '["dirk-muller"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-raSRTUkjjLrZ', 'Six Sigma für Dummies', 'Includes index.', 'book', '["craig-gygi", "bruce-williams", "neil-decarlo"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-E5uENuxFdwOr', 'Statistik mit Excel für Dummies', 'A comprehensive guide to using Excel for statistical analysis, this book simplifies complex statistical concepts and techniques, making them accessible for beginners. Written by Joseph Schmuller, it covers data analysis, hypothesis testing, and regression, providing practical examples and step-by-step instructions for leveraging Excel''s powerful features.', 'book', '["joseph-schmuller"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
