INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-ocTmmscYYc87', 'Statistik für Dummies', 'A comprehensive guide to understanding and applying statistical concepts, tailored for beginners. It breaks down complex ideas into simple, easy-to-follow explanations with practical examples, making it accessible for readers without a background in statistics.', 'book', '["deborah-j-rumsey"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
