INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-ai0JDC9kz4le', 'Das Quark und der Jaguar', 'A profound exploration of the complexities of nature, where the author, a Nobel Prize-winning physicist, delves into the interconnectedness of simple and complex phenomena, examining topics from particle physics to the processes of human consciousness and the universe''s intricate tapestry.', 'book', '["murray-gell-mann"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-dl-tJXLrboMK', 'Einsteins Universum', 'A comprehensive exploration of Einstein''s theories, delving into the concepts of relativity and their impact on our understanding of the universe, presented in an accessible manner for a broad audience.', 'book', '["nigel-calder"]', '["science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-UWsoKaP8FZ_c', 'Kitsch ist Geschmackssache', 'Explores the subjective nature of taste and kitsch, examining cultural, social, and personal factors that influence perceptions of aesthetic value.', 'book', '["anja-weber"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-eBeYLxrTwmfJ', 'Der Traum von der Einheit des Universums', 'A comprehensive exploration of the quest for a unified theory of fundamental forces, reflecting on the history, challenges, and scientific milestones in physics.', 'book', '["steven-weinberg"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-X3FOviQbQ2qy', 'Der grosse Entwurf', 'A groundbreaking exploration of the universe''s origins and the nature of reality, "Der grosse Entwurf" delves into topics such as the theory of everything, quantum theory, and the laws of nature, offering insights into how the universe began and how it is governed.', 'book', '["stephen-hawking", "leonard-mlodinow"]', '["science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-pmrwOETwDPnn', 'Das Universum in der Nussschale', 'A thought-provoking exploration of key concepts in theoretical physics, including the nature of time, the possibility of time travel, and the mysteries of black holes and the universe, presented in an accessible format by renowned physicist Stephen Hawking.', 'book', '["stephen-hawking"]', '["science"]', NULL, '2026-05-11 23:09:48');
