INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-GAXhU10xJi0-', 'Asterix – Gesamtausgabe, Band 15', 'Band 15 schließt die Kunstleder-Asterix-Gesamtausgabe ab und versammelt die drei jüngsten Ferri/Conrad-Alben: ''Die Tochter des Vercingetorix'' (ein gallischer Teenager-Erbe mit Identitätskrise), ''Asterix und der Greif'' (Reise zu den Sarmaten) und ''Die weiße Iris'' (Konfrontation mit einer Wohlfühl-Psycho-Bewegung). Als Sonderbonus enthalten: ''Der Goldene Hinkelstein'' (Originalstory in Bilderbuch-Form). Mit umfangreichem editorischem Anhang von Horst Berner als Abschluss der Reihe.', 'book', '["rene-goscinny", "albert-uderzo", "jean-yves-ferri", "didier-conrad"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-dD8moanDvduC', 'Asterix – Gesamtausgabe, Band 14', 'Band 14 der Asterix-Gesamtausgabe enthält die beiden Ferri/Conrad-Alben ''Der Papyrus des Cäsar'' (ein brisantes Dokument bedroht Cäsars Ruhm) und ''Asterix in Italien'' (ein Wagenrennen quer durch Italien). Als Bonus zusätzlich das Filmalbum ''Asterix erobert Rom''. Mit ausführlichen Hintergrund-Essays zum Schaffen des neuen Autorenteams.', 'book', '["rene-goscinny", "albert-uderzo", "jean-yves-ferri", "didier-conrad"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-qAeCHMkgVvlV', 'Asterix – Gesamtausgabe, Band 13', 'Band 13 der Asterix-Gesamtausgabe vereint ''Asterix und Obelix feiern Geburtstag'' (ein Jubiläumsband mit 56 Seiten Comic-Material und einer Galerie von rund 400 Asterix-Charakteren) sowie ''Asterix bei den Pikten'' (das erste Album des neuen Teams Ferri/Conrad mit den unbeugsamen Galliern in Schottland). Inklusive Skizzen zu ''Asterix bei den Pikten''.', 'book', '["rene-goscinny", "albert-uderzo", "jean-yves-ferri", "didier-conrad"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-jmf10yuvIDs8', 'Asterix – Gesamtausgabe, Band 12', 'Band 12 der Asterix-Gesamtausgabe enthält ''Asterix plaudert aus der Schule'' (eine Sammlung von 14 Kurzgeschichten) und das letzte Solo-Album Uderzos ''Gallien in Gefahr'' (eine außerirdische Bedrohung erschüttert das Dorf). Inklusive umfangreichem Skizzenteil zu ''Gallien in Gefahr''.', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-xkSMYYrKT3qK', 'Asterix – Gesamtausgabe, Band 11', 'Band 11 der Asterix-Gesamtausgabe enthält ''Asterix und Maestria'' (eine Reporterin bringt das traditionelle Dorf in Aufruhr), ''Obelix auf Kreuzfahrt'' (eine Zaubertrank-Panne führt nach Atlantis) und ''Asterix und Latraviata'' (eine römische Agentin auf einem turbulenten Geburtstagsfest). Mit aktualisierten Vorworten von Horst Berner.', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-mUp8I_aYmrZc', 'Asterix – Gesamtausgabe, Band 10', 'Band 10 der Asterix-Gesamtausgabe vereint ''Asterix im Morgenland'' (Rettung einer indischen Prinzessin) mit der Origin-Story ''Wie Obelix als kleines Kind in den Zaubertrank geplumpst ist'', die erklärt, woher Obelix'' permanente Superkraft stammt. Zusätzlich enthalten: Skizzen und unveröffentlichtes Material von Uderzo.', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-SwIsBM75fayl', 'Asterix – Gesamtausgabe, Band 9', 'Band 9 der Asterix-Gesamtausgabe enthält die ersten Uderzo-Solo-Abenteuer: ''Der große Graben'' (ein durch rivalisierende Häuptlinge gespaltenes Dorf), ''Die Odyssee'' (Reise in den Nahen Osten und Suche nach Steinöl-Ersatz) und ''Der Sohn des Asterix'' (das mysteriöse Findelkind). Mit Kontext zur Übergangsphase nach Goscinnys Tod.', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-eSgKQhWjw32U', 'Asterix – Gesamtausgabe, Band 8', 'Band 8 der Asterix-Gesamtausgabe vereint drei Goscinny-Klassiker: ''Die große Überfahrt'' (versehentliche Entdeckung der Neuen Welt), ''Obelix GmbH & Co. KG'' (Obelix als Hinkelstein-Industriemagnat) und ''Asterix bei den Belgiern'' (das letzte Album, das Goscinny vor seinem Tod 1977 vollendete). Mit ausführlichem Vorwort zum Vermächtnis Goscinnys.', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-JTUjGHtjP1wt', 'Asterix – Gesamtausgabe, Band 7', 'Band 7 der Asterix-Gesamtausgabe enthält ''Der Seher'' (ein falscher Wahrsager nutzt den Aberglauben der Dorfbewohner), ''Asterix auf Korsika'' (Befreiung eines korsischen Gefangenen und Besuch auf der Insel) und ''Das Geschenk Cäsars'' (ein Legionär erhält das gallische Dorf als Ruhestandsgeschenk). Mit redaktionellen Vorworten und Begleitmaterial.', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-btPNMnQoOSAd', 'Asterix – Gesamtausgabe, Band 6', 'Band 6 der Asterix-Gesamtausgabe bringt drei Klassiker: ''Asterix bei den Schweizern'' (Reise in die Alpen für seltene Edelweiße), ''Die Trabantenstadt'' (Cäsar will eine römische Großsiedlung um das Dorf bauen) und ''Die Lorbeeren des Cäsar'' (Asterix muss Cäsars Lorbeerkranz beschaffen). Sorgfältig neu koloriert mit modernisierter Comic-Schrift.', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-6AnG_8qIYOlH', 'Asterix – Gesamtausgabe, Band 5', 'Band 5 der Asterix-Gesamtausgabe enthält ''Asterix und der Kupferkessel'' (ein verschwundener Schatz und unverdienter Verdacht), ''Asterix in Spanien'' (die Befreiung des Goten-Geiselkindes Pepe) und ''Streit um Asterix'' (der Römer Tullius Destructivus säht Zwietracht im Dorf). Mit umfangreichem Begleitmaterial.', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-kkk1HBojmskY', 'Asterix – Gesamtausgabe, Band 4', 'Band 4 der Asterix-Gesamtausgabe vereint drei Abenteuer rund um militärische und sportliche Herausforderungen: ''Asterix als Legionär'' (Falbalas Verlobter Tragicomix wird gerettet), ''Asterix und der Arvernerschild'' (Majestix erbt das Symbol Vercingetorix'' und Cäsar will es) und ''Asterix bei den Olympischen Spielen'' (Wettkampf in Olympia gegen Claudius Musculus). Neu koloriert, mit Vorworten von Horst Berner.', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-TuoSvF9I02nC', 'Asterix – Gesamtausgabe, Band 3', 'Band 3 der Asterix-Gesamtausgabe enthält ''Der Kampf der Häuptlinge'' (ein römertreuer Häuptling fordert Majestix heraus), ''Asterix bei den Briten'' (Vetter Teefax und der gallische Zaubertrank in England) und ''Asterix und die Normannen'' (die wikingerähnlichen Nordmänner wollen das Gruseln lernen). Mit erweiterten Vorworten und Sekundärmaterial.', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-2hh--Og3q9fv', 'Asterix – Gesamtausgabe, Band 2', 'Band 2 der Asterix-Gesamtausgabe versammelt drei der beliebtesten Reise-Abenteuer: ''Asterix als Gladiator'' (Rettung des entführten Troubadix in Rom), ''Tour de France'' (kulinarische Rundreise durch Gallien) und ''Asterix und Kleopatra'' (Hilfe beim Palastbau für die Pharaonin). Sorgfältig neu koloriert, mit Hintergrund-Essays von Horst Berner.', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-5OHLK-KDZ9Ki', 'Asterix – Gesamtausgabe, Band 1', 'Band 1 der Asterix-Gesamtausgabe von Egmont Ehapa: die drei ersten Klassiker der Serie in neu kolorierter, neu geletterter Fassung. Enthält ''Asterix der Gallier'' (das Ur-Abenteuer mit dem Zaubertrank), ''Die goldene Sichel'' und ''Asterix und die Goten''. Mit ausführlichen redaktionellen Vorworten von Horst Berner zu jeder Geschichte sowie illustrierten Sekundär-Artikeln und Skizzen.', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-O6WqE3XTpgJJ', 'Der Wüstenkrieg in Afrika', 'A comprehensive account of the North African conflict during World War II, exploring key battles, strategies, and military leaders, with detailed analyses and historical photographs. Published in 1984, this work by Janusz Piekalkiewicz offers an in-depth exploration of the war efforts in the desert landscapes of Africa.', 'book', '["janusz-piekalkiewicz"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-dJWYij-GbnTv', 'Seekrieg', 'A comprehensive exploration of naval warfare during World War II, detailing strategies, battles, and the impact of maritime conflicts with supporting illustrations and firsthand accounts.', 'book', '["janusz-piekalkiewicz"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-6Dr0HH2evyuI', 'Invasion', 'A historical account examining the strategies, tactics, and events of significant military invasions, detailing the complexities and consequences of these operations throughout history. Published in 1974 by Janusz Piekalkiewicz, this work offers insights into military history with an emphasis on factual reporting and analysis.', 'book', '["janusz-piekalkiewicz"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-gQNMtwcO74vz', 'Luftkrieg', 'A comprehensive examination of aerial warfare during World War II, detailing strategies, significant battles, and technological advancements. The book combines historical analysis with firsthand accounts, providing a vivid portrayal of the impact of air power on the war''s outcome.', 'book', '["janusz-piekalkiewicz"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-oKpgBrrX81Zm', 'Der Präzisions-Luftkrieg gegen Land und Leute', 'A comprehensive analysis of the impact and strategies of precision air warfare on civilian populations and landscapes, exploring both historical and modern contexts.', 'book', '["raimund-muller"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-e7olJ1w1qCSW', 'Der Zweite Weltkrieg', 'A comprehensive examination of the events, strategies, and key figures of World War II, providing insights into the global impact and historical significance of the conflict. Published in 1985 by author R. Oldenbourg, this work delves into the detailed narratives and analysis that shaped the course of 20th-century history.', 'book', '["r-oldenbourg"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-xNLuudOROR2L', 'Der Erste Weltkrieg', 'Comprehensive historical account of World War I, detailing major battles, strategies, and political influences, supported by photographs and firsthand accounts.', 'book', '["janusz-piekalkiewicz"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-67IhUMr0ENuB', 'Flugzeugbewaffnung', 'An exploration of the development and technology of aircraft armament, detailing the evolution of weaponry and systems used in aviation, with insights into historical milestones and technical advancements by esteemed aviation author Bill Gunston.', 'book', '["bill-gunston"]', '["history"]', NULL, '2026-05-11 23:09:48');
COMMIT;
